import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Typography, 
  Box, 
  Paper, 
  Grid, 
  Button, 
  Card, 
  CardContent, 
  CardActions,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  CircularProgress,
  Alert,
  IconButton,
  Tooltip
} from '@mui/material';
import { 
  AccountBalanceWallet, 
  ContentCopy, 
  Add,
  Visibility,
  VisibilityOff
} from '@mui/icons-material';
import axios from 'axios';

const Wallets = () => {
  const [wallets, setWallets] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [openDialog, setOpenDialog] = useState(false);
  const [walletFormData, setWalletFormData] = useState({
    name: '',
    currency: 'USD',
  });
  const [formError, setFormError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showPrivateKeys, setShowPrivateKeys] = useState({});
  const [copySuccess, setCopySuccess] = useState('');

  const currencies = ['USD', 'EUR', 'GBP', 'CAD', 'JPY', 'USDC', 'USDT', 'ETH', 'BTC'];

  useEffect(() => {
    fetchWallets();
  }, []);

  const fetchWallets = async () => {
    setLoading(true);
    setError(null);

    try {
      const response = await axios.get('/wallet/');
      setWallets(response.data);
    } catch (err) {
      console.error('Error fetching wallets:', err);
      setError('Failed to load wallets. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleCreateWallet = async () => {
    setFormError('');
    setIsSubmitting(true);

    try {
      // Validate form data
      if (!walletFormData.name.trim()) {
        setFormError('Wallet name is required');
        setIsSubmitting(false);
        return;
      }

      const response = await axios.post('/wallet/', walletFormData);
      setWallets([...wallets, response.data]);
      setOpenDialog(false);
      resetFormData();
    } catch (err) {
      console.error('Error creating wallet:', err);
      setFormError(err.response?.data?.detail || 'Failed to create wallet. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const resetFormData = () => {
    setWalletFormData({
      name: '',
      currency: 'USD',
    });
  };

  const handleDialogClose = () => {
    setOpenDialog(false);
    resetFormData();
    setFormError('');
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setWalletFormData({
      ...walletFormData,
      [name]: value
    });
  };

  const togglePrivateKeyVisibility = (walletId) => {
    setShowPrivateKeys({
      ...showPrivateKeys,
      [walletId]: !showPrivateKeys[walletId]
    });
  };

  const copyToClipboard = (text, type) => {
    navigator.clipboard.writeText(text).then(
      () => {
        setCopySuccess(`${type} copied!`);
        setTimeout(() => setCopySuccess(''), 2000);
      },
      () => {
        setCopySuccess('Failed to copy');
      }
    );
  };

  const formatCurrency = (amount, currency = 'USD') => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency
    }).format(amount);
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Paper sx={{ p: 3 }}>
          <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
            <Typography variant="h4" component="h1">
              Your Wallets
            </Typography>
            <Button 
              variant="contained" 
              startIcon={<Add />}
              onClick={() => setOpenDialog(true)}
            >
              New Wallet
            </Button>
          </Box>

          {error && (
            <Alert severity="error" sx={{ mb: 3 }}>
              {error}
            </Alert>
          )}

          {copySuccess && (
            <Alert severity="success" sx={{ mb: 3 }}>
              {copySuccess}
            </Alert>
          )}

          {wallets.length === 0 ? (
            <Box textAlign="center" py={5}>
              <AccountBalanceWallet sx={{ fontSize: 60, color: 'text.secondary', mb: 2 }} />
              <Typography variant="h6" gutterBottom>
                No Wallets Found
              </Typography>
              <Typography variant="body1" color="text.secondary" paragraph>
                You haven't created any wallets yet. Create your first wallet to start sending and receiving payments.
              </Typography>
              <Button 
                variant="contained" 
                startIcon={<Add />}
                onClick={() => setOpenDialog(true)}
              >
                Create Your First Wallet
              </Button>
            </Box>
          ) : (
            <Grid container spacing={3}>
              {wallets.map((wallet) => (
                <Grid item xs={12} md={6} lg={4} key={wallet.id}>
                  <Card>
                    <CardContent>
                      <Typography variant="h6" gutterBottom>
                        {wallet.name}
                      </Typography>
                      <Typography variant="h4" component="div" gutterBottom>
                        {formatCurrency(wallet.balance, wallet.currency)}
                      </Typography>

                      <Box sx={{ mt: 2 }}>
                        <Typography variant="subtitle2" color="text.secondary">
                          Wallet Address
                        </Typography>
                        <Box display="flex" alignItems="center">
                          <Typography variant="body2" sx={{ wordBreak: 'break-all', mr: 1 }}>
                            {wallet.address}
                          </Typography>
                          <Tooltip title="Copy Address">
                            <IconButton 
                              size="small"
                              onClick={() => copyToClipboard(wallet.address, 'Address')}
                            >
                              <ContentCopy fontSize="small" />
                            </IconButton>
                          </Tooltip>
                        </Box>
                      </Box>

                      <Box sx={{ mt: 2 }}>
                        <Typography variant="subtitle2" color="text.secondary">
                          Private Key
                        </Typography>
                        <Box display="flex" alignItems="center">
                          <Typography variant="body2" sx={{ wordBreak: 'break-all', mr: 1 }}>
                            {showPrivateKeys[wallet.id] 
                              ? wallet.private_key 
                              : '••••••••••••••••••••••••••••••••••'}
                          </Typography>
                          <Tooltip title={showPrivateKeys[wallet.id] ? "Hide Private Key" : "Show Private Key"}>
                            <IconButton 
                              size="small"
                              onClick={() => togglePrivateKeyVisibility(wallet.id)}
                            >
                              {showPrivateKeys[wallet.id] ? <VisibilityOff fontSize="small" /> : <Visibility fontSize="small" />}
                            </IconButton>
                          </Tooltip>
                          {showPrivateKeys[wallet.id] && (
                            <Tooltip title="Copy Private Key">
                              <IconButton 
                                size="small"
                                onClick={() => copyToClipboard(wallet.private_key, 'Private Key')}
                              >
                                <ContentCopy fontSize="small" />
                              </IconButton>
                            </Tooltip>
                          )}
                        </Box>
                      </Box>
                    </CardContent>
                    <CardActions>
                      <Button size="small" color="primary">
                        Send
                      </Button>
                      <Button size="small">
                        View Transactions
                      </Button>
                    </CardActions>
                  </Card>
                </Grid>
              ))}
            </Grid>
          )}
        </Paper>
      </Box>

      {/* New Wallet Dialog */}
      <Dialog open={openDialog} onClose={handleDialogClose} fullWidth maxWidth="sm">
        <DialogTitle>Create New Wallet</DialogTitle>
        <DialogContent>
          {formError && (
            <Alert severity="error" sx={{ mb: 2 }}>
              {formError}
            </Alert>
          )}

          <TextField
            autoFocus
            margin="dense"
            name="name"
            label="Wallet Name"
            type="text"
            fullWidth
            variant="outlined"
            value={walletFormData.name}
            onChange={handleInputChange}
            sx={{ mb: 2 }}
          />

          <FormControl fullWidth variant="outlined">
            <InputLabel id="currency-select-label">Currency</InputLabel>
            <Select
              labelId="currency-select-label"
              id="currency-select"
              name="currency"
              value={walletFormData.currency}
              onChange={handleInputChange}
              label="Currency"
            >
              {currencies.map((currency) => (
                <MenuItem key={currency} value={currency}>
                  {currency}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleDialogClose} color="inherit">
            Cancel
          </Button>
          <Button 
            onClick={handleCreateWallet} 
            color="primary" 
            variant="contained"
            disabled={isSubmitting}
          >
            {isSubmitting ? 'Creating...' : 'Create Wallet'}
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default Wallets;
